// Define Vector2 struct
struct Vector2<T> {
    x: T,
    y: T,
}

impl<T: Copy + std::ops::Add<Output=T>> std::ops::Add for Vector2<T> {
    type Output = Vector2<T>;
    fn add(self, other: Self) -> Self {
        Vector2 { x: self.x + other.x, y: self.y + other.y }
    }
}

